"use strict";
(function(){
	try{
		var root = document.documentElement;
		root.classList.add("theme-preload");

		if (!document.getElementById("biotern-theme-preload-style")) {
			var style = document.createElement("style");
			style.id = "biotern-theme-preload-style";
			style.textContent = "html.theme-preload *,html.theme-preload *::before,html.theme-preload *::after{transition:none!important;animation:none!important;}";
			document.head.appendChild(style);
		}

		function readCookie(name){
			var key = name + "=";
			var parts = document.cookie ? document.cookie.split(";") : [];
			for (var i = 0; i < parts.length; i++) {
				var chunk = parts[i].trim();
				if (chunk.indexOf(key) === 0) return chunk.substring(key.length);
			}
			return "";
		}

		var prefs = null;
		try {
			var raw = readCookie("biotern_theme_preferences");
			if (raw) prefs = JSON.parse(decodeURIComponent(raw));
		} catch (e) {}

		function getStored(modeKey, darkClass){
			var v = localStorage.getItem(modeKey) || "";
			return v.indexOf("dark") !== -1 || v === darkClass ? "dark" : "light";
		}

		var allowedFonts = [
			"app-font-family-inter",
			"app-font-family-lato",
			"app-font-family-rubik",
			"app-font-family-cinzel",
			"app-font-family-nunito",
			"app-font-family-roboto",
			"app-font-family-ubuntu",
			"app-font-family-poppins",
			"app-font-family-raleway",
			"app-font-family-system-ui",
			"app-font-family-noto-sans",
			"app-font-family-fira-sans",
			"app-font-family-work-sans",
			"app-font-family-open-sans",
			"app-font-family-maven-pro",
			"app-font-family-quicksand",
			"app-font-family-montserrat",
			"app-font-family-josefin-sans",
			"app-font-family-ibm-plex-sans",
			"app-font-family-source-sans-pro",
			"app-font-family-montserrat-alt",
			"app-font-family-roboto-slab"
		];

		var skin = prefs && (prefs.skin === "dark" || prefs.skin === "light")
			? prefs.skin
			: ((localStorage.getItem("app-skin-dark") || localStorage.getItem("app-skin") || localStorage.getItem("app_skin") || localStorage.getItem("theme") || "").indexOf("dark") !== -1 ? "dark" : "light");

		var navigation = prefs && (prefs.navigation === "dark" || prefs.navigation === "light")
			? prefs.navigation
			: getStored("app-navigation", "app-navigation-dark");

		var header = prefs && (prefs.header === "dark" || prefs.header === "light")
			? prefs.header
			: getStored("app-header", "app-header-dark");

		var font = prefs && typeof prefs.font === "string" ? prefs.font : (localStorage.getItem("font-family") || "default");

		if (skin === "dark") root.classList.add("app-skin-dark");
		if (navigation === "dark") root.classList.add("app-navigation-dark");
		if (header === "dark") root.classList.add("app-header-dark");

		if (font && font !== "default" && allowedFonts.indexOf(font) !== -1) {
			var cls = root.className || "";
			root.className = cls.replace(/\bapp-font-family-[^\s]+\b/g, "").replace(/\s{2,}/g, " ").trim();
			root.classList.add(font);
		}
	}catch(e){}
})();
